## Plan

1. Promisify dependencies with `util.promisify` (tx methods need per-instance binding).
2. Implement core logic in `processOrderAsync` with try/catch per fallible step; cleanup branches mirror the original reverse-order sequence and swallow cleanup errors via `.catch(() => {})`.
3. `tx.commit` failure propagates without cleanup (matches original — tx state is unknown after commit failure).
4. Notifier failure is caught locally and only warned; `order` still returned.
5. Public `processOrder(orderId, userId, items, callback)` is a thin adapter: `.then(ok, err)` → `callback`. Use `process.nextTick` so callback is always async and so throws inside the callback don't become unhandled rejections.

## Code

```javascript
// lib/order_processor.js
const { promisify } = require('util');
const db = require('./db');
const payment = require('./payment');
const inventory = require('./inventory');
const notifier = require('./notifier');

const startTransaction = promisify(db.startTransaction);
const saveOrder = promisify(db.saveOrder);
const reserve = promisify(inventory.reserve);
const release = promisify(inventory.release);
const chargePayment = promisify(payment.charge);
const refund = promisify(payment.refund);
const notify = promisify(notifier.send);

const commitTx = (tx) => promisify(tx.commit.bind(tx))();
const rollbackTx = (tx) => promisify(tx.rollback.bind(tx))();

async function processOrderAsync(orderId, userId, items) {
  const tx = await startTransaction();

  let reservation;
  try {
    reservation = await reserve(tx, items);
  } catch (err) {
    await rollbackTx(tx).catch(() => {});
    throw err;
  }

  let charge;
  try {
    charge = await chargePayment(userId, reservation.total);
  } catch (err) {
    await release(tx, reservation.id).catch(() => {});
    await rollbackTx(tx).catch(() => {});
    throw err;
  }

  let order;
  try {
    order = await saveOrder(tx, orderId, {
      userId, items, reservationId: reservation.id, chargeId: charge.id,
    });
  } catch (err) {
    await refund(charge.id).catch(() => {});
    await release(tx, reservation.id).catch(() => {});
    await rollbackTx(tx).catch(() => {});
    throw err;
  }

  await commitTx(tx);

  try {
    await notify(userId, 'order_placed', order);
  } catch (notifyErr) {
    console.warn('notify failed:', notifyErr);
  }

  return order;
}

function processOrder(orderId, userId, items, callback) {
  processOrderAsync(orderId, userId, items).then(
    (order) => process.nextTick(callback, null, order),
    (err) => process.nextTick(callback, err),
  );
}

module.exports = { processOrder };
```

Semantic parity: same cleanup order on each failure path, cleanup errors swallowed, commit-failure path has no cleanup, notify failure is warn-only, callback signature unchanged.
